hold_ticks := 0
if ((#Door #FrontDoor).door_doorState == "closed") {
hold_ticks = hold_ticks + 1
    if (hold_ticks >= 599) {
(#Plug #Switch #LivingRoom #AC).switch_on()
        break
}
}
else {
hold_ticks = 0
}

